1	import { describe, it, expect } from "vitest";
2	import { scalePixelArt } from "./pixel-art-scaler.js";
3	
4	describe("Pixel Art Scaler", () => {
5	  it("should return empty image for empty input regardless of scale factor", () => {
6	    expect(scalePixelArt([], 2)).toEqual([]);
7	  });
8	  it("should return unchanged image for scale factor of 1", () => {
9	    expect(scalePixelArt([["A", "B"], ["C", "D"]], 1)).toEqual([["A", "B"], ["C", "D"]]);
10	  });
11	  it("should scale a single pixel horizontally and vertically by factor 2", () => {
12	    expect(scalePixelArt([["A"]], 2)).toEqual([["A", "A"], ["A", "A"]]);
13	  });
14	  it("should replicate each pixel exactly scale times in a single-row image", () => {
15	    expect(scalePixelArt([["A", "B"]], 3)).toEqual([
16	      ["A", "A", "A", "B", "B", "B"],
17	      ["A", "A", "A", "B", "B", "B"],
18	      ["A", "A", "A", "B", "B", "B"],
19	    ]);
20	  });
21	  it("should replicate each row exactly scale times in a single-column image", () => {
22	    expect(scalePixelArt([["A"], ["B"]], 3)).toEqual([
23	      ["A", "A", "A"],
24	      ["A", "A", "A"],
25	      ["A", "A", "A"],
26	      ["B", "B", "B"],
27	      ["B", "B", "B"],
28	      ["B", "B", "B"],
29	    ]);
30	  });
31	  it.todo("should scale a multi-pixel single-row image by factor 2");
32	  it.todo("should scale a multi-row image horizontally and vertically by factor 2");
33	  it.todo("should preserve character values exactly when scaling");
34	});
